//   _failureReason: err.status >= 500 → 'http_5xx'
// HttpError(500) is retryable (not 4xx), so all 3 attempts fail → catch → http_5xx

import { jest } from '@jest/globals';

jest.unstable_mockModule('../../src/core/logger.js', () => ({
